```js
export const convert = (digits, inputBase, outputBase) => {
  if (inputBase < 2) throw new Error('Wrong input base');
  if (outputBase < 2) throw new Error('Wrong output base');
  if (digits.length === 0) throw new Error('Input has wrong format');
  if (digits.some(d => d < 0 || d >= inputBase)) throw new Error('Input has wrong format');
  if (digits.length > 1 && digits[0] === 0) throw new Error('Input has wrong format');

  let value = digits.reduce((acc, d) => acc * inputBase + d, 0);

  if (value === 0) return [0];
  const result = [];
  while (value > 0) {
    result.unshift(value % outputBase);
    value = Math.floor(value / outputBase);
  }
  return result;
};
```

The algorithm:
1. Validates input/output bases (must be ≥ 2)
2. Validates digits (non-empty, no negatives, no values ≥ inputBase, no leading zeros)
3. Converts digits to a decimal value using reduce
4. Converts that value to the output base using repeated division

